// ============================================================================
// BOARD MODE core loop v3.0 — reconciles game.js res{} with spin-and-climb.
// Snake = SQUARES[40], each {idx, x, y, type, label?, need?, cardPool?, fork?}.
// Practical: a turn is one breath of a startup's life — a decision, a roll of
// luck, a climb that costs you, and whatever the board had waiting where you stop.
// Philosophical: the molecule rises on capital, not hypotheses. The board never
// lies about that. Neither do we.
// ============================================================================

const IDLE_BURN = 4;            // burn-rate overhead every turn (FIX-2)
const FIRST_TO_FILE = 36;      // the dog's 'they filed first' line
const BANKRUPT_FLOOR = 8;      // land on idx24 under this -> forced bust

function takeTurn(deckId) {
  if (S.status !== 'playing') return;

  // (1) DRAW — player agency. Random card from chosen deck; flip anim + sound.
  const card = drawFromDeck(deckId);              // shuffled-without-replacement pool
  playFlip(card);                                 // card-flip CSS + Web-Audio tick
  applyDeckBase(deckId, card);                    // capital/data/goodwill/readiness
  if (deckId === 'enroll' && card.dirty) { S.integrity++; S.dogSurge = 1.5; }
  if (deckId === 'fda')   { S.competitorPos = Math.max(0, S.competitorPos - 1); }

  // (2) IDLE BURN — stalling is never free. The lights stay on whether you move
  //     or not; this is what makes parking below a gate a real bleed (FIX-2).
  S.res.capital -= IDLE_BURN;
  if (clampAndCheckEnd()) return;

  // (3) SPIN — chance. Wedge 1 also refunds $4 so low isn't strictly best (FIX-4).
  const { steps, capBonus } = spin();             // steps 1..4
  if (capBonus) S.res.capital += capBonus;
  animateSpinner(steps);

  // (4) CLIMB — burn per square, gate-intercept, submission ALWAYS stops, fail-loud.
  let moved = 0;
  while (moved < steps && S.pos < 39) {
    const here = SQUARES[S.pos];
    // submission gate is the boss door: it ALWAYS halts the climb (FIX-1).
    if (here.idx === 38) {
      if (S.readiness >= here.need && !S.reviewOpened) { S.reviewOpened = true; return openReview(); }
      break;                                      // not ready -> stall at Vance's door
    }
    // milestone gate: pay to pass, else stop AT it (no overshoot).
    if (here.type === 'gate') {
      if (S.readiness < here.need) break;
      S.readiness -= here.need;                    // keep the remainder as head-start
    }
    S.pos += 1;
    S.res.capital -= burn(S.pos);                  // 2.8 + 0.05*idx, climbing cost
    animateCatTo(S.pos);
    if (S.res.capital <= 0) return lose('bankrupt');   // mid-climb death
    moved++;
  }

  // (5) LAND — fire ONLY the final square's trigger (funding pays HERE now, FIX-3).
  land(SQUARES[S.pos]);
  if (S.status !== 'playing') return;

  // (6) END OF TURN — the dog gains, the clock ticks.
  advanceCompetitor();                            // dogStep + dogSurge
  S.dogSurge = 0; S.turn++;
  if (clampAndCheckEnd()) return;
  renderAll();
}

function land(sq) {
  switch (sq.type) {
    case 'gate':                                   // a non-submission gate you stalled at
      return;                                      // render shows lock + readiness bar
    case 'fork':                                   // painted Sell/CEO/CRO — always fires
      if (sq.idx === 26 && S.res.capital < BANKRUPT_FLOOR) return forceSell();  // broke -> forced buyout
      return showChoice(sq.card);
    case 'funding':                                // grant@3 / boot@11 / corp@27 — pay on LAND only
      return refundFundingSquare(sq.idx);
    case 'trigger':                                // good/bad/swing REG card
      if (sq.idx === 24 && S.res.capital < BANKRUPT_FLOOR) return lose('bankrupt'); // out-of-money square
      return resolveCard(sq.cardPool.draw());
    case 'terminal':                               // idx39 reached only via afterReview(APPROVED)
      S.status = 'won'; S.outcome = 'approved'; return endGame();
    default: return;                               // plain — a breath between hazards
  }
}

function burn(idx) { return Math.round((2.8 + 0.05 * idx) * 10) / 10; }
function spin()    { const w = 1 + Math.floor(Math.random() * 4); return { steps: w, capBonus: w === 1 ? 4 : 0 }; }

function advanceCompetitor() {
  const step = (1.1 + 0.18 * S.difficulty) * (S.char.competitorMult || 1);
  S.competitorPos += step + (S.dogSurge || 0);
  if (S.competitorPos >= FIRST_TO_FILE && !S.clearedSubmission) {
    if (S.char.id === 'investor' && !S.investorSaveUsed) {       // one-time lifeline (FIX-5)
      S.investorSaveUsed = true; S.competitorPos = 30;
      pushLog('A delay at the competitor\'s site buys you one more turn.', 'good'); return;
    }
    return lose('beaten_to_market');                              // Scooped at the Buzzer
  }
}

// afterReview(APPROVED) is the ONLY path to idx39 — it does S.pos = 39 then land()/endGame,
// so Dr. Vance is on 100% of winning runs (FIX-1).

function clampAndCheckEnd() {
  clamp();                                  // bound data/goodwill 0-100; capital/pos unclamped
  if (S.res.capital <= 0)   return lose('bankrupt');
  if (S.turn > S.maxTurns)  return lose('failed_endpoint');             // runway gone
  if (S.res.reputation <= 0 && atSubmissionGate()) return lose('clinical_hold');
  return false;
}
// computeScore() / endGame() / rankTitle() reused; board pos feeds valuePct.
// valuePct DROPPED from APPROVED score (constant for winners); kept in ACQUIRED (FIX-7).

// ============================================================================
// ## changelog from critique
// FIX-1 (P1, Dr. Vance): submission gate@38 ALWAYS halts the climb; loop never
//   walks 38->39; afterReview(APPROVED) is the sole path to idx39. The boss and
//   her LLM verdict + integrity ledger + typed-rationale climax now fire on 100%
//   of winners (was: skipped entirely on the happy path).
// FIX-2 (P1, stall-park): IDLE_BURN=$4M charged every turn before the climb, so
//   not-moving still bleeds runway-cash. Start capital re-tuned 120->112; maxTurns
//   28->22 so the clock actually bites (winners finish ~turn 16, ~6 slack).
// FIX-3 (P1, pass-through): funding squares pay on LAND only (moved into land()),
//   removing ~$46M of free pass-through money; payouts bumped (grant 28, corp 36,
//   boot +24/-12) to compensate for rarity. Routing-to-land is now real skill.
// FIX-4 (P2, spinner): wedge 1 refunds +$4M ('slow & frugal') and, with land-only
//   funding, high spins risk overshooting a square you wanted — neither extreme
//   dominant; the spinner is a genuine risk dial, not 'pray for 1s'.
// FIX-5 (P1, dog/difficulty): replaced broken ceil(55/(16-d+3))(==4 for all d)
//   with explicit dogStep=(1.1+0.18*d)*mult (1.28..2.00); BURN_NORMALIZER deleted.
//   Investor mult 1.25->1.10 + one-time scoop-save lifeline (8%->99.3% win); its
//   upside now touches the live fail axis.
// FIX-6 (P2, readiness/clean-play): total gate need 80->58 (8/10/12/16/12), R&D
//   readiness 5->6, so a CLEAN R&D-only build fits 22 turns alongside the climb —
//   both clean and dirty(Enroll, integrity-taxed) lines viable; four decks matter.
// FIX-7 (P2, scoring): dropped valuePct*7 from APPROVED (constant 679 for all
//   winners); redistributed to varying terms (capitalLeft*4, data*5, goodwill*3,
//   reviewMod*15 now reachable, turnsLeft 40->25); integrity tax -30->-20 so a
//   dirty win is taxed, not auto-bottom. valuePct*9 kept in ACQUIRED.
// FIX-P3 (placement): forks@16/21/26 + bankruptcy@24 sit where mean-2.5 spins from
//   gate stops (15->16-19, 23->24-27) land them >40% of runs; canon squares fire.
// Re-verified: PowerShell Monte-Carlo, 5000 runs/cfg — careful d3 ~98.6% win @
//   ~19% capital spare turn ~16; reckless never-fund 100% bankrupt; difficulty
//   scoop 0%(d1)->6.4%(d5); every founder winnable. The design CLOSES.
// ============================================================================
